import { Effect } from "effect"
import { WasmRuntime } from "./WasmRuntime"
import {
  KeygenError,
  SigningError,
  HintGenerationError,
  PackingError,
  VerificationError,
} from "./errors"
import type {
  FalconKeypair,
  FalconSignatureResult,
  PackedPublicKey,
} from "./types"

// ---------------------------------------------------------------------------
// VK byte deserialization
// ---------------------------------------------------------------------------

/**
 * Deserialize a Falcon-512 verifying key (897 bytes) into 512 NTT-domain
 * coefficients stored as an Int32Array.
 *
 * Format (falcon-rs encoding.rs):
 *   - Byte 0:      1-byte header (falcon algorithm/degree tag) — SKIPPED
 *   - Bytes 1-896: 512 coefficients x 14 bits each, packed LSB-first
 *
 * Algorithm: maintains a bit-buffer, loading bytes from the input one at a
 * time and extracting 14-bit windows.
 *
 * Throws on invalid input (too few bytes, or any coefficient >= Q=12289).
 */
function deserializePublicKeyNtt(vkBytes: Uint8Array): Int32Array {
  const Q = 12289
  const N = 512
  const BITS_PER_COEFF = 14
  const DATA_BYTES = (N * BITS_PER_COEFF) / 8 // 896

  // Byte 0 is the Falcon header tag (e.g. 0x09 for Falcon-512).
  // The 896 bytes of coefficient data start at index 1.
  if (vkBytes.length < 1 + DATA_BYTES) {
    throw new Error(
      `VK too short: expected at least ${1 + DATA_BYTES} bytes, got ${vkBytes.length}`,
    )
  }

  const coeffs = new Int32Array(N)
  const mask = (1 << BITS_PER_COEFF) - 1 // 0x3FFF

  let bitBuffer = 0
  let bitsInBuffer = 0
  let byteIndex = 1 // skip header byte

  for (let i = 0; i < N; i++) {
    while (bitsInBuffer < BITS_PER_COEFF) {
      bitBuffer |= vkBytes[byteIndex++] << bitsInBuffer
      bitsInBuffer += 8
    }
    const coeff = bitBuffer & mask
    bitBuffer >>= BITS_PER_COEFF
    bitsInBuffer -= BITS_PER_COEFF

    if (coeff >= Q) {
      throw new Error(
        `Invalid VK coefficient ${coeff} at index ${i} (must be < ${Q})`,
      )
    }
    coeffs[i] = coeff
  }

  return coeffs
}

// ---------------------------------------------------------------------------
// FalconService
// ---------------------------------------------------------------------------

export class FalconService extends Effect.Service<FalconService>()(
  "FalconService",
  {
    accessors: true,
    // No pre-bundled dependencies: callers must provide WasmRuntime via Layer.
    // This enables unit tests to inject a mock WasmRuntime without the live
    // loader trying to fetch /wasm/falcon_rs.js at import time.
    effect: Effect.gen(function* () {
      const wasm = yield* WasmRuntime

      const generateKeypair = Effect.fn("Falcon.generateKeypair")(
        function* (seed?: Uint8Array) {
          const s =
            seed ?? crypto.getRandomValues(new Uint8Array(32))
          const result = yield* Effect.try({
            try: () => wasm.keygen(s),
            catch: (error) =>
              new KeygenError({ message: String(error) }),
          })
          const publicKeyNtt = yield* Effect.try({
            try: () => deserializePublicKeyNtt(result.vk),
            catch: (error) =>
              new KeygenError({ message: String(error) }),
          })
          return {
            secretKey: result.sk,
            verifyingKey: result.vk,
            publicKeyNtt,
          } satisfies FalconKeypair
        },
      )

      const sign = Effect.fn("Falcon.sign")(
        function* (
          secretKey: Uint8Array,
          message: Uint8Array,
        ) {
          const result = yield* Effect.try({
            try: () =>
              wasm.sign(secretKey, message, new Uint8Array(0)),
            catch: (error) =>
              new SigningError({ message: String(error) }),
          })
          return result satisfies FalconSignatureResult
        },
      )

      const verify = Effect.fn("Falcon.verify")(
        function* (
          verifyingKey: Uint8Array,
          message: Uint8Array,
          signature: Uint8Array,
        ) {
          return yield* Effect.try({
            try: () => wasm.verify(verifyingKey, message, signature),
            catch: (error) =>
              new VerificationError({
                message: String(error),
                step: "verify",
              }),
          })
        },
      )

      const createHint = Effect.fn("Falcon.createHint")(
        function* (
          s1: Int32Array,
          pkNtt: Int32Array,
        ) {
          return yield* Effect.try({
            try: () => wasm.create_verification_hint(s1, pkNtt),
            catch: (error) =>
              new HintGenerationError({ message: String(error) }),
          })
        },
      )

      const packPublicKey = Effect.fn("Falcon.packPublicKey")(
        function* (
          pkNtt: Uint16Array,
        ) {
          const slots = yield* Effect.try({
            try: () => wasm.pack_public_key_wasm(pkNtt),
            catch: (error) =>
              new PackingError({ message: String(error) }),
          })
          return { slots } satisfies PackedPublicKey
        },
      )

      return {
        generateKeypair,
        sign,
        verify,
        createHint,
        packPublicKey,
      }
    }),
  },
) {}

/**
 * Tests for FalconService -- verify-playground category.
 *
 * Coverage requirements:
 * - Every Effect service method must have at least one success and one failure test
 * - WasmRuntime is mocked via Layer.succeed so no real WASM is needed
 */

import { describe, it, expect } from "bun:test"
import { Cause, Effect, Exit, Layer, Option } from "effect"
import { WasmRuntime } from "../../services/WasmRuntime"
import { FalconService } from "../../services/FalconService"
import type { WasmModule } from "../../services/WasmRuntime"

// ---------------------------------------------------------------------------
// Mock WASM module factories
// ---------------------------------------------------------------------------

const makeSuccessWasm = (): WasmModule => ({
  keygen: (_seed) => ({
    sk: new Uint8Array(1281).fill(1),
    vk: new Uint8Array(897).fill(2),
  }),
  sign: (_sk, _msg, _salt) => ({
    signature: new Uint8Array(666).fill(3),
    salt: new Uint8Array(40).fill(4),
  }),
  verify: (_vk, _msg, _sig) => true,
  create_verification_hint: (_s1, _pkNtt) =>
    new Uint16Array(512).fill(0),
  pack_public_key_wasm: (_pkNtt) =>
    Array.from({ length: 29 }, (_, i) => `0x${i.toString(16).padStart(64, "0")}`),
  public_key_length: () => 897,
  salt_length: () => 40,
})

const makeFailingWasm = (): WasmModule => ({
  keygen: () => {
    throw new Error("keygen failed in WASM")
  },
  sign: () => {
    throw new Error("signing failed in WASM")
  },
  verify: () => {
    throw new Error("verification failed in WASM")
  },
  create_verification_hint: () => {
    throw new Error("hint generation failed in WASM")
  },
  pack_public_key_wasm: () => {
    throw new Error("packing failed in WASM")
  },
  public_key_length: () => 897,
  salt_length: () => 40,
})

// Layer helpers
const makeSuccessLayer = () =>
  Layer.succeed(WasmRuntime, makeSuccessWasm())

const makeFailingLayer = () =>
  Layer.succeed(WasmRuntime, makeFailingWasm())

/** Run an effect provided with a specific WasmRuntime mock */
async function runWith<A, E>(
  effect: Effect.Effect<A, E, FalconService>,
  wasmLayer: Layer.Layer<WasmRuntime>,
): Promise<Exit.Exit<A, E>> {
  // FalconService.Default provides FalconService using its registered dependencies.
  // We override the WasmRuntime dependency via Layer.provide.
  const serviceLayer = FalconService.Default.pipe(
    Layer.provide(wasmLayer),
  )
  return Effect.runPromiseExit(effect.pipe(Effect.provide(serviceLayer)))
}

// ---------------------------------------------------------------------------
// generateKeypair
// ---------------------------------------------------------------------------

// VK mock (897 bytes, all 0x02): produces deterministic known coefficients.
// Header byte (index 0) is skipped during deserialization.
// Data bytes 1..896 = 0x02, 14-bit LSB-first unpacking produces repeating pattern:
//   coeff[0]=514, coeff[1]=2056, coeff[2]=8224, coeff[3]=128 (period 4)
const KNOWN_VK_MOCK = new Uint8Array(897).fill(2)

// VK mock that produces coefficient >= Q (12289), causing KeygenError.
// With all bytes = 0xFF: first 14 bits = 0b11111111111111 = 16383 >= 12289.
const INVALID_COEFF_VK = new Uint8Array(897).fill(0xff)

// VK mock that is too short to contain 512 x 14-bit coefficients.
const TOO_SHORT_VK = new Uint8Array(10).fill(2)

describe("FalconService.generateKeypair", () => {
  it("succeeds and returns a FalconKeypair", async () => {
    const exit = await runWith(
      FalconService.generateKeypair(new Uint8Array(32)),
      makeSuccessLayer(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value.secretKey).toBeInstanceOf(Uint8Array)
      expect(exit.value.verifyingKey).toBeInstanceOf(Uint8Array)
      expect(exit.value.publicKeyNtt).toBeInstanceOf(Int32Array)
    }
  })

  it("publicKeyNtt has length 512", async () => {
    const exit = await runWith(
      FalconService.generateKeypair(new Uint8Array(32)),
      makeSuccessLayer(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value.publicKeyNtt.length).toBe(512)
    }
  })

  it("publicKeyNtt contains non-zero deserialized coefficients (not all zeros)", async () => {
    const exit = await runWith(
      FalconService.generateKeypair(new Uint8Array(32)),
      makeSuccessLayer(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      const ntt = exit.value.publicKeyNtt
      const hasNonZero = Array.from(ntt).some((v) => v !== 0)
      expect(hasNonZero).toBe(true)
    }
  })

  it("publicKeyNtt contains known coefficients for fill(2) VK mock", async () => {
    // VK = Uint8Array(897).fill(2): byte 0 is header (skipped), bytes 1-896 are data.
    // 14-bit LSB-first unpacking of repeating 0x02 bytes gives pattern:
    // coeff[0]=514, coeff[1]=2056, coeff[2]=8224, coeff[3]=128 (repeating every 4)
    const mockWasm: WasmModule = {
      ...makeSuccessWasm(),
      keygen: (_seed) => ({ sk: new Uint8Array(1281).fill(1), vk: KNOWN_VK_MOCK }),
    }
    const exit = await runWith(
      FalconService.generateKeypair(new Uint8Array(32)),
      Layer.succeed(WasmRuntime, mockWasm),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      const ntt = exit.value.publicKeyNtt
      expect(ntt.length).toBe(512)
      expect(ntt[0]).toBe(514)
      expect(ntt[1]).toBe(2056)
      expect(ntt[2]).toBe(8224)
      expect(ntt[3]).toBe(128)
      // All coefficients must be in [0, Q) where Q = 12289
      for (let i = 0; i < 512; i++) {
        expect(ntt[i]).toBeGreaterThanOrEqual(0)
        expect(ntt[i]).toBeLessThan(12289)
      }
    }
  })

  it("fails with KeygenError when VK has out-of-range coefficients (>= Q)", async () => {
    // fill(0xFF) produces 14-bit value 16383 >= Q=12289 -> KeygenError
    const mockWasm: WasmModule = {
      ...makeSuccessWasm(),
      keygen: (_seed) => ({ sk: new Uint8Array(1281).fill(1), vk: INVALID_COEFF_VK }),
    }
    const exit = await runWith(
      FalconService.generateKeypair(new Uint8Array(32)),
      Layer.succeed(WasmRuntime, mockWasm),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      const err = Cause.failureOption(exit.cause)
      expect(Option.isSome(err)).toBe(true)
      if (Option.isSome(err)) {
        expect(err.value._tag).toBe("KeygenError")
      }
    }
  })

  it("fails with KeygenError when VK bytes are too short", async () => {
    const mockWasm: WasmModule = {
      ...makeSuccessWasm(),
      keygen: (_seed) => ({ sk: new Uint8Array(1281).fill(1), vk: TOO_SHORT_VK }),
    }
    const exit = await runWith(
      FalconService.generateKeypair(new Uint8Array(32)),
      Layer.succeed(WasmRuntime, mockWasm),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      const err = Cause.failureOption(exit.cause)
      expect(Option.isSome(err)).toBe(true)
      if (Option.isSome(err)) {
        expect(err.value._tag).toBe("KeygenError")
      }
    }
  })

  it("succeeds without explicit seed (uses crypto.getRandomValues)", async () => {
    const exit = await runWith(
      FalconService.generateKeypair(),
      makeSuccessLayer(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
  })

  it("fails with KeygenError when WASM keygen throws", async () => {
    const exit = await runWith(
      FalconService.generateKeypair(new Uint8Array(32)),
      makeFailingLayer(),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      const err = Cause.failureOption(exit.cause)
      expect(Option.isSome(err)).toBe(true)
      if (Option.isSome(err)) {
        expect(err.value._tag).toBe("KeygenError")
      }
    }
  })
})

// ---------------------------------------------------------------------------
// sign
// ---------------------------------------------------------------------------

describe("FalconService.sign", () => {
  const sk = new Uint8Array(1281).fill(1)
  const msg = new TextEncoder().encode("Hello, Falcon!")

  it("succeeds and returns a FalconSignatureResult", async () => {
    const exit = await runWith(
      FalconService.sign(sk, msg),
      makeSuccessLayer(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value.signature).toBeInstanceOf(Uint8Array)
      expect(exit.value.salt).toBeInstanceOf(Uint8Array)
    }
  })

  it("fails with SigningError when WASM throws", async () => {
    const exit = await runWith(
      FalconService.sign(sk, msg),
      makeFailingLayer(),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      const err = Cause.failureOption(exit.cause)
      expect(Option.isSome(err)).toBe(true)
      if (Option.isSome(err)) {
        expect(err.value._tag).toBe("SigningError")
      }
    }
  })
})

// ---------------------------------------------------------------------------
// verify
// ---------------------------------------------------------------------------

describe("FalconService.verify", () => {
  const vk = new Uint8Array(897).fill(2)
  const msg = new TextEncoder().encode("Hello, Falcon!")
  const sig = new Uint8Array(666).fill(3)

  it("succeeds and returns true for valid signature", async () => {
    const exit = await runWith(
      FalconService.verify(vk, msg, sig),
      makeSuccessLayer(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value).toBe(true)
    }
  })

  it("succeeds and returns false when mock wasm returns false", async () => {
    const falseWasm: WasmModule = {
      ...makeSuccessWasm(),
      verify: () => false,
    }
    const exit = await runWith(
      FalconService.verify(vk, msg, sig),
      Layer.succeed(WasmRuntime, falseWasm),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value).toBe(false)
    }
  })

  it("fails with VerificationError when WASM throws", async () => {
    const exit = await runWith(
      FalconService.verify(vk, msg, sig),
      makeFailingLayer(),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      const err = Cause.failureOption(exit.cause)
      expect(Option.isSome(err)).toBe(true)
      if (Option.isSome(err)) {
        expect(err.value._tag).toBe("VerificationError")
      }
    }
  })
})

// ---------------------------------------------------------------------------
// createHint
// ---------------------------------------------------------------------------

describe("FalconService.createHint", () => {
  const s1 = new Int32Array(512).fill(1)
  const pkNtt = new Int32Array(512).fill(2)

  it("succeeds and returns a Uint16Array hint", async () => {
    const exit = await runWith(
      FalconService.createHint(s1, pkNtt),
      makeSuccessLayer(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value).toBeInstanceOf(Uint16Array)
      expect(exit.value.length).toBe(512)
    }
  })

  it("fails with HintGenerationError when WASM throws", async () => {
    const exit = await runWith(
      FalconService.createHint(s1, pkNtt),
      makeFailingLayer(),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      const err = Cause.failureOption(exit.cause)
      expect(Option.isSome(err)).toBe(true)
      if (Option.isSome(err)) {
        expect(err.value._tag).toBe("HintGenerationError")
      }
    }
  })
})

// ---------------------------------------------------------------------------
// packPublicKey
// ---------------------------------------------------------------------------

describe("FalconService.packPublicKey", () => {
  const pkNtt = new Uint16Array(512).fill(100)

  it("succeeds and returns 29 felt252 hex slots", async () => {
    const exit = await runWith(
      FalconService.packPublicKey(pkNtt),
      makeSuccessLayer(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value.slots.length).toBe(29)
      for (const slot of exit.value.slots) {
        expect(slot).toMatch(/^0x/)
      }
    }
  })

  it("fails with PackingError when WASM throws", async () => {
    const exit = await runWith(
      FalconService.packPublicKey(pkNtt),
      makeFailingLayer(),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      const err = Cause.failureOption(exit.cause)
      expect(Option.isSome(err)).toBe(true)
      if (Option.isSome(err)) {
        expect(err.value._tag).toBe("PackingError")
      }
    }
  })
})

// ---------------------------------------------------------------------------
// deserializePublicKeyNtt
// ---------------------------------------------------------------------------

describe("FalconService.deserializePublicKeyNtt", () => {
  it("succeeds with a valid all-zero 897-byte VK and returns 512 Int32Array coefficients", async () => {
    // 897 bytes: byte 0 = header (0x09 for Falcon-512), bytes 1-896 = all-zero coefficient data
    // all-zero bit stream → all-zero 14-bit windows → all coefficients = 0 < Q=12289 ✓
    const validVk = new Uint8Array(897)
    validVk[0] = 0x09
    const exit = await runWith(
      FalconService.deserializePublicKeyNtt(validVk),
      makeSuccessLayer(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value).toBeInstanceOf(Int32Array)
      expect(exit.value.length).toBe(512)
      expect(exit.value.every((c) => c === 0)).toBe(true)
    }
  })

  it("fails with KeygenError when VK is too short (< 897 bytes)", async () => {
    const shortVk = new Uint8Array(10)
    const exit = await runWith(
      FalconService.deserializePublicKeyNtt(shortVk),
      makeSuccessLayer(),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      const err = Cause.failureOption(exit.cause)
      expect(Option.isSome(err)).toBe(true)
      if (Option.isSome(err)) {
        expect(err.value._tag).toBe("KeygenError")
      }
    }
  })
})

/**
 * Tests for verify-playground Schema.TaggedError classes.
 *
 * Coverage requirements:
 * - Every Schema.TaggedError must be constructable and matchable
 * - _tag must equal the class name string
 */

import { describe, it, expect } from "bun:test"
import { Effect, Exit, Cause, Option } from "effect"
import {
  WasmLoadError,
  KeygenError,
  SigningError,
  VerificationError,
  HintGenerationError,
  PackingError,
} from "../../services/errors"

describe("WasmLoadError", () => {
  it("is constructable with a message", () => {
    const err = new WasmLoadError({ message: "failed to load wasm" })
    expect(err.message).toBe("failed to load wasm")
    expect(err._tag).toBe("WasmLoadError")
  })

  it("can be used as Effect failure and matched by _tag", async () => {
    const effect = Effect.fail(
      new WasmLoadError({ message: "module missing" }),
    )
    const exit = await Effect.runPromiseExit(effect)
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      const err = Cause.failureOption(exit.cause)
      expect(Option.isSome(err)).toBe(true)
      if (Option.isSome(err)) {
        expect(err.value._tag).toBe("WasmLoadError")
        expect(err.value.message).toBe("module missing")
      }
    }
  })

  it("can be caught with catchTag", async () => {
    let caught = false
    const effect = Effect.fail(
      new WasmLoadError({ message: "oops" }),
    ).pipe(
      Effect.catchTag("WasmLoadError", () => {
        caught = true
        return Effect.succeed("recovered")
      }),
    )
    const result = await Effect.runPromise(effect)
    expect(result).toBe("recovered")
    expect(caught).toBe(true)
  })
})

describe("KeygenError", () => {
  it("is constructable with a message", () => {
    const err = new KeygenError({ message: "keygen failed" })
    expect(err.message).toBe("keygen failed")
    expect(err._tag).toBe("KeygenError")
  })

  it("roundtrips through Effect failure", async () => {
    const exit = await Effect.runPromiseExit(
      Effect.fail(new KeygenError({ message: "seed error" })),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      const err = Cause.failureOption(exit.cause)
      expect(Option.isSome(err)).toBe(true)
      if (Option.isSome(err)) {
        expect(err.value._tag).toBe("KeygenError")
      }
    }
  })
})

describe("SigningError", () => {
  it("is constructable with a message", () => {
    const err = new SigningError({ message: "signing failed" })
    expect(err.message).toBe("signing failed")
    expect(err._tag).toBe("SigningError")
  })

  it("roundtrips through Effect failure", async () => {
    const exit = await Effect.runPromiseExit(
      Effect.fail(new SigningError({ message: "sig err" })),
    )
    expect(Exit.isFailure(exit)).toBe(true)
  })
})

describe("VerificationError", () => {
  it("is constructable with message and step", () => {
    const err = new VerificationError({
      message: "norm check failed",
      step: "norm-check",
    })
    expect(err.message).toBe("norm check failed")
    expect(err.step).toBe("norm-check")
    expect(err._tag).toBe("VerificationError")
  })

  it("can be caught by _tag", async () => {
    let caughtStep = ""
    await Effect.runPromise(
      Effect.fail(
        new VerificationError({ message: "bad sig", step: "verify" }),
      ).pipe(
        Effect.catchTag("VerificationError", (e) => {
          caughtStep = e.step
          return Effect.succeed(null)
        }),
      ),
    )
    expect(caughtStep).toBe("verify")
  })
})

describe("HintGenerationError", () => {
  it("is constructable with a message", () => {
    const err = new HintGenerationError({ message: "hint failed" })
    expect(err.message).toBe("hint failed")
    expect(err._tag).toBe("HintGenerationError")
  })

  it("fails the effect on failure", async () => {
    const exit = await Effect.runPromiseExit(
      Effect.fail(new HintGenerationError({ message: "ntt error" })),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    expect(Exit.isSuccess(exit)).toBe(false)
  })
})

describe("PackingError", () => {
  it("is constructable with a message", () => {
    const err = new PackingError({ message: "pack failed" })
    expect(err.message).toBe("pack failed")
    expect(err._tag).toBe("PackingError")
  })

  it("fails the effect on failure", async () => {
    const exit = await Effect.runPromiseExit(
      Effect.fail(new PackingError({ message: "slots error" })),
    )
    expect(Exit.isFailure(exit)).toBe(true)
  })
})

/**
 * Tests for verify-playground atom state (initial values and transitions).
 *
 * Coverage requirements:
 * - Every atom must have its initial value verified
 * - State transitions are tested via registry.set + registry.get
 */

import { describe, it, expect } from "bun:test"
import { Option } from "effect"
import { Registry } from "@effect-atom/atom"
import {
  wasmStatusAtom,
  keypairAtom,
  verificationStepAtom,
  messageAtom,
  signatureAtom,
} from "../../atoms/falcon"
import type { FalconKeypair } from "../../services/types"

// Helper: create a fresh registry per test (isolated state)
function makeRegistry() {
  return Registry.make()
}

describe("wasmStatusAtom", () => {
  it("has initial value 'loading'", () => {
    const registry = makeRegistry()
    expect(registry.get(wasmStatusAtom)).toBe("loading")
  })

  it("transitions to 'ready'", () => {
    const registry = makeRegistry()
    registry.set(wasmStatusAtom, "ready")
    expect(registry.get(wasmStatusAtom)).toBe("ready")
  })

  it("transitions to 'error'", () => {
    const registry = makeRegistry()
    registry.set(wasmStatusAtom, "error")
    expect(registry.get(wasmStatusAtom)).toBe("error")
  })

  it("transitions loading → ready → error → loading", () => {
    const registry = makeRegistry()
    expect(registry.get(wasmStatusAtom)).toBe("loading")
    registry.set(wasmStatusAtom, "ready")
    expect(registry.get(wasmStatusAtom)).toBe("ready")
    registry.set(wasmStatusAtom, "error")
    expect(registry.get(wasmStatusAtom)).toBe("error")
    registry.set(wasmStatusAtom, "loading")
    expect(registry.get(wasmStatusAtom)).toBe("loading")
  })
})

describe("keypairAtom", () => {
  it("has initial value Option.none()", () => {
    const registry = makeRegistry()
    expect(Option.isNone(registry.get(keypairAtom))).toBe(true)
  })

  it("transitions to Some(keypair) after setting", () => {
    const registry = makeRegistry()
    const mockKeypair: FalconKeypair = {
      secretKey: new Uint8Array(1281),
      verifyingKey: new Uint8Array(897),
      publicKeyNtt: new Int32Array(512),
    }
    registry.set(keypairAtom, Option.some(mockKeypair))
    const val = registry.get(keypairAtom)
    expect(Option.isSome(val)).toBe(true)
    if (Option.isSome(val)) {
      expect(val.value.secretKey).toBeInstanceOf(Uint8Array)
      expect(val.value.verifyingKey).toBeInstanceOf(Uint8Array)
      expect(val.value.publicKeyNtt).toBeInstanceOf(Int32Array)
    }
  })

  it("can be reset to Option.none()", () => {
    const registry = makeRegistry()
    const mockKeypair: FalconKeypair = {
      secretKey: new Uint8Array(1281),
      verifyingKey: new Uint8Array(897),
      publicKeyNtt: new Int32Array(512),
    }
    registry.set(keypairAtom, Option.some(mockKeypair))
    expect(Option.isSome(registry.get(keypairAtom))).toBe(true)
    registry.set(keypairAtom, Option.none())
    expect(Option.isNone(registry.get(keypairAtom))).toBe(true)
  })
})

describe("verificationStepAtom", () => {
  it("has initial value { step: 'idle' }", () => {
    const registry = makeRegistry()
    const val = registry.get(verificationStepAtom)
    expect(val.step).toBe("idle")
  })

  it("transitions to generating-keypair", () => {
    const registry = makeRegistry()
    registry.set(verificationStepAtom, { step: "generating-keypair" })
    expect(registry.get(verificationStepAtom).step).toBe(
      "generating-keypair",
    )
  })

  it("transitions to signing", () => {
    const registry = makeRegistry()
    registry.set(verificationStepAtom, { step: "signing" })
    expect(registry.get(verificationStepAtom).step).toBe("signing")
  })

  it("transitions to creating-hint", () => {
    const registry = makeRegistry()
    registry.set(verificationStepAtom, { step: "creating-hint" })
    expect(registry.get(verificationStepAtom).step).toBe("creating-hint")
  })

  it("transitions to packing", () => {
    const registry = makeRegistry()
    registry.set(verificationStepAtom, { step: "packing" })
    expect(registry.get(verificationStepAtom).step).toBe("packing")
  })

  it("transitions to verifying with substep", () => {
    const registry = makeRegistry()
    registry.set(verificationStepAtom, {
      step: "verifying",
      substep: "ntt",
    })
    const val = registry.get(verificationStepAtom)
    expect(val.step).toBe("verifying")
    if (val.step === "verifying") {
      expect(val.substep).toBe("ntt")
    }
  })

  it("transitions to complete with result", () => {
    const registry = makeRegistry()
    registry.set(verificationStepAtom, {
      step: "complete",
      valid: true,
      durationMs: 42,
    })
    const val = registry.get(verificationStepAtom)
    expect(val.step).toBe("complete")
    if (val.step === "complete") {
      expect(val.valid).toBe(true)
      expect(val.durationMs).toBe(42)
    }
  })

  it("transitions to error with message", () => {
    const registry = makeRegistry()
    registry.set(verificationStepAtom, {
      step: "error",
      message: "WASM crash",
    })
    const val = registry.get(verificationStepAtom)
    expect(val.step).toBe("error")
    if (val.step === "error") {
      expect(val.message).toBe("WASM crash")
    }
  })

  it("full happy-path transition sequence", () => {
    const registry = makeRegistry()
    const steps: string[] = []

    // Walk through the full verification pipeline
    for (const s of [
      { step: "generating-keypair" },
      { step: "signing" },
      { step: "creating-hint" },
      { step: "packing" },
      { step: "verifying", substep: "ntt-s1" },
      { step: "complete", valid: true, durationMs: 1234 },
    ] as const) {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      registry.set(verificationStepAtom, s as any)
      steps.push(registry.get(verificationStepAtom).step)
    }

    expect(steps).toEqual([
      "generating-keypair",
      "signing",
      "creating-hint",
      "packing",
      "verifying",
      "complete",
    ])
  })
})

describe("messageAtom", () => {
  it("has initial value empty string", () => {
    const registry = makeRegistry()
    expect(registry.get(messageAtom)).toBe("")
  })

  it("transitions to a non-empty message", () => {
    const registry = makeRegistry()
    registry.set(messageAtom, "Hello, Starknet!")
    expect(registry.get(messageAtom)).toBe("Hello, Starknet!")
  })

  it("can be cleared back to empty string", () => {
    const registry = makeRegistry()
    registry.set(messageAtom, "some message")
    registry.set(messageAtom, "")
    expect(registry.get(messageAtom)).toBe("")
  })
})

describe("signatureAtom", () => {
  it("has initial value Option.none()", () => {
    const registry = makeRegistry()
    expect(Option.isNone(registry.get(signatureAtom))).toBe(true)
  })

  it("can be set to Some(signature)", () => {
    const registry = makeRegistry()
    registry.set(signatureAtom, Option.some({
      signature: new Uint8Array(666),
      salt: new Uint8Array(40),
    }))
    const val = registry.get(signatureAtom)
    expect(Option.isSome(val)).toBe(true)
    if (Option.isSome(val)) {
      expect(val.value.signature).toBeInstanceOf(Uint8Array)
      expect(val.value.salt).toBeInstanceOf(Uint8Array)
    }
  })
})

